1.用户登录import java.util.Scanner;public class A322 &#123;	public static void main(String[] args)	&#123;	//数组定义时，[]中的数字指的是“长度”，而不是最大下标值！		String[] user = new String[5];		String[] passwd = new String[5];		user[0] = &quot;admin1&quot;;		user[1] = &quot;admin2&quot;;		user[2] = &quot;admin3&quot;;		user[3] = &quot;admin4&quot;;		user[4] = &quot;admin5&quot;;		passwd[0] = &quot;test1&quot;;		passwd[1] = &quot;test2&quot;;		passwd[2] = &quot;test3&quot;;		passwd[3] = &quot;test4&quot;;		passwd[4] = &quot;test5&quot;;	      int x = 0;	      boolean flag = false;	      String users, passwds;	      while (x&lt;3) 	      &#123;	    	  //使用扫描器来接收输入的用户名和密码	          Scanner sc = new Scanner(System.in);	          System.out.println(&quot;请输入用户名：&quot;);	          users = sc.nextLine();;	          System.out.println(&quot;请输入密码：&quot;);	          passwds = sc.nextLine();	          	          for (int i = 0; i &lt; user.length; i++) 	          &#123;	              if (users.equals(user[i]) &amp;&amp; passwds.equals(passwd[i])) 	              &#123;	                  flag = true;	                  //退出整体循环	                  break;	              &#125;	          &#125;	          if (flag) 	          &#123;	              System.out.println(&quot;登录成功&quot;);	              //登录成功，跳出while循环！	              break;	          &#125;	          else	        	  &#123;	        	  System.out.println(&quot;用户名或密码错误&quot;);	        	  ++x;	        	  &#125;	         	      &#125;	      //while	      if (x == 3)	      &#123;	          System.out.println(&quot;三次登录机会已经用完&quot;);	      &#125;	&#125;&#125;

2.利用数组的写法import java.util.Scanner;import javax.swing.JOptionPane;public class B322 &#123;	public static void main(String[] args)	&#123;		String username[]= &#123;&quot;aa&quot;,&quot;bb&quot;,&quot;cc&quot;,&quot;dd&quot;,&quot;ee&quot;&#125;;		String password[]= &#123;&quot;1&quot;,&quot;2&quot;,&quot;3&quot;,&quot;4&quot;,&quot;5&quot;&#125;;		int i;	    int nCounter = 0;       	    	do	    	&#123;	    		String strName=	    	    		JOptionPane.showInputDialog(&quot;请输用户名&quot;);	    	    String strPassword=	    	    		JOptionPane.showInputDialog(&quot;请输密码&quot;);	    		for (i = 0; i &lt; username.length; i++)	    		&#123;	    		   if (strName.equals(username[i]))	    		   &#123;	    			   break;	    		   &#125;	    		&#125;	    			    		if (i &lt; 5)	    		&#123;	    			if (strPassword.equals(password[i]))	    			   &#123;	    				   JOptionPane.showMessageDialog(null,	&quot;登录成功！&quot;);	    				   System.exit(0);	    			   &#125;	    			   else	    			   &#123;	    			       nCounter++;	    			       JOptionPane.showMessageDialog(null,	&quot;密码输入错误！&quot;); 	    			   &#125;	    		&#125;	    			    		if (5 == i)	    		&#123;	    			nCounter++;	    			JOptionPane.showMessageDialog(null,	&quot;用户名输入错误！&quot;);	    				    		&#125;	    			    	&#125;while(nCounter &lt; 3);	    		    	if(3 == nCounter)		    &#123;	    		JOptionPane.showMessageDialog(null,	&quot;用户名或密码输入错误已达3次，程序将退出！&quot;);		    	System.exit(0);		    &#125;  		&#125;&#125;

3.矩形public class 矩形&#123;	//属性-成员变量:全局变量	float 长,宽,周长,面积;	//功能-成员方法		//构造方法:1.方法的名字和类的名字完全一致	//		  2.构造方法没有返回值,void省略不写	//		3.构造方法的作用只有一个:给成员变量赋初值	矩形(float x,float y)	&#123;		长=x;		宽=y;	&#125;	float 计算周长()	&#123;		周长=(长+宽)*2;		return 周长;	&#125;	float 计算面积()	&#123;		面积=长*宽;		return 面积;	&#125;	void 修改长(float x)	&#123;		长=x;	&#125;	void 修改宽(float y)	&#123;		宽=y;	&#125;	float 获取长()	&#123;		return 长;	&#125;	float 获取宽()	&#123;		return 宽;	&#125;&#125;

public class DemoC322&#123;	public static void main(String[] args)	&#123;		//对象的声明		矩形 Iphone999;		//对象的创建;		Iphone999=new 矩形(13.6f,2.5f);				//Iphone999.长-直接访问&quot;成员变量&quot;		System.out.println(&quot;Iphone999的长是&quot;+Iphone999.长);		//Iphone999.获取宽()-调用&quot;成员方法&quot;		System.out.println(&quot;Iphone999的长是&quot;+Iphone999.获取宽());		System.out.println(&quot;Iphone999的周长是&quot;+Iphone999.计算周长());		System.out.println(&quot;Iphone999的面积是&quot;+Iphone999.计算面积());				Iphone999.修改宽(4.3f);		System.out.println(&quot;Iphone999的面积是&quot;+Iphone999.计算面积());	&#125;&#125;

1.圆public class 圆 &#123;	float r,c,s;	圆(float r)	&#123;	//构造半径		this.r=r;	&#125;	void setr(float r)	&#123;	//设置半径变量		this.r=r;	&#125;	float getr()	&#123;		return r;	&#125;	//周长	float 计算c()	&#123;		c=2*3.14f*r;		return r;	&#125;	//面积	float 计算s()	&#123;		s=3.14f*r*r;		return s;	&#125;&#125;

