1.三角形public class 三角形 &#123;	//成员变量	double a,b,c,len;	boolean flag=false;//判断是否是三角形	//成员方法：先构造，再get/set,最后其他	public 三角形(double a, double b, double c) &#123;		if(panDuan(a,b,c))		&#123;			this.a = a;			this.b = b;			this.c = c;					&#125;		else		&#123;			System.out.println(&quot;三边长度不构成三角形！&quot;);		&#125;	&#125;	public boolean panDuan(double a,double b,double c)	&#123;		if(a+b&gt;c&amp;&amp;a+c&gt;b&amp;&amp;b+c&gt;a)		&#123;			flag = true;		&#125;		else		&#123;			flag=false;		&#125;		return flag;	&#125;		public 三角形(double a) &#123;		super();		this.b = this.c = this.a=a;	&#125;		public double getA() &#123;		return a;	&#125;	public void setA(double a) &#123;		this.a = a;	&#125;	public double getB() &#123;		return b;	&#125;	public void setB(double b) &#123;		this.b = b;	&#125;	public double getC() &#123;		return c;	&#125;	public void setC(double c) &#123;		this.c = c;	&#125;		double 计算周长()	&#123;		if(flag)		&#123;			len=a+b+c;		&#125;		return len;	&#125;&#125;

