import java.awt.*;import java.awt.event.*;import javax.swing.*;public class Demo &#123;	public static JComboBox comboBox;	public static JButton add,del,bt_luck;	public static JTextArea tA;	private static JTextField textField;		public static void main(String[] args) 	&#123;		JFrame MyFrame=new JFrame(&quot;实训12&quot;);		MyFrame.setSize(300,269);		MyFrame.getContentPane().setLayout(null);				/*JComboBox*/ comboBox = new JComboBox();		comboBox.setModel(new DefaultComboBoxModel(new String[] &#123;&quot;11&quot;, &quot;22&quot;, &quot;33&quot;, &quot;44&quot;, &quot;55&quot;, &quot;66&quot;, &quot;77&quot;, &quot;88&quot;, &quot;99&quot;, &quot;00&quot;&#125;));		comboBox.setBounds(29, 25, 59, 23);		MyFrame.getContentPane().add(comboBox);				/*JButton*/ add = new JButton(&quot;\u589E\u52A0&quot;);		add.setBounds(109, 25, 71, 23);		MyFrame.getContentPane().add(add);				/*JButton*/ del = new JButton(&quot;\u5220\u9664&quot;);		del.setBounds(183, 25, 71, 23);		MyFrame.getContentPane().add(del);				textField = new JTextField();		textField.setBounds(29, 58, 59, 21);		MyFrame.getContentPane().add(textField);		textField.setColumns(10);				JScrollPane scrollPane = new JScrollPane();		scrollPane.setBounds(29, 100, 227, 98);		MyFrame.getContentPane().add(scrollPane);				/*JTextArea*/ tA = new JTextArea();		scrollPane.setColumnHeaderView(tA);				/*JButton*/ bt_luck = new JButton(&quot;\u62BD\u5956&quot;);		bt_luck.setBounds(109, 58, 145, 23);		MyFrame.getContentPane().add(bt_luck);		MyFrame.setVisible(true);				ActionListener a=new ActionListener() 		&#123;						@Override			public void actionPerformed(ActionEvent e) 			&#123;				//添加				if(e.getSource()==add)				&#123;					 int i;					 String name= textField.getText();					 					 if(name.length()&gt;0)					 &#123;						 //遍历下拉列表，检验是否重复						 for(i=0;i&lt;comboBox.getItemCount();i++)						 &#123;							 if(name.equals(comboBox.getItemAt(i)))							 &#123;								 JOptionPane.showMessageDialog(null,&quot;用户已存在,重新输入&quot;);								 textField.setText(&quot;&quot;);								 break;							 &#125;						 &#125;						 if(i==comboBox.getItemCount())						 &#123;							 tA.append(&quot;\n添加&quot;+name);//将操作的内容显示在文本区中							 comboBox.addItem(name); //添加textField里的内容作为新的一项							 comboBox.setSelectedIndex(comboBox.getItemCount()-1);//将新添 加的一项设置为选中状态						 &#125;							 &#125;					 else					 &#123;						 JOptionPane.showMessageDialog(null,&quot;用户姓名不能为空,重新输入&quot;);					 &#125;				&#125;								//删除				if(e.getSource()==del)								&#123;					tA.append(&quot;\n删除&quot;+comboBox.getSelectedItem());//将操作的内容显示在文本区中   					comboBox.removeItemAt( comboBox.getSelectedIndex());				&#125;								//抽奖				if(e.getSource()==bt_luck)				&#123;					int i =(int)(Math.random()*comboBox.getItemCount());					tA.append(&quot;恭喜&quot;+comboBox.getItemAt(i)+&quot;中奖了&quot;+&quot;\n&quot;);				&#125;			&#125;		&#125;;	   		del.addActionListener(a);//为“添加”按钮添加监视器		add.addActionListener(a);//为“删除”按钮添加监视器		bt_luck.addActionListener(a);//为“抽奖”按钮添加监视器				ItemListener b=new ItemListener() //定义按钮的监视器		&#123;			@Override			public void itemStateChanged(ItemEvent e) 			&#123;			if(e.getStateChange()==e.SELECTED)//这里控制为只处理一次&#123;			&#123;				int index=comboBox.getSelectedIndex();				String name=(String)comboBox.getSelectedItem();				tA.append(&quot;\n&quot;+index+&quot;:&quot;+name);			&#125;							&#125;		&#125;;		comboBox.addItemListener(b);	&#125;&#125;

