t;);					tf_2.setText(&quot;&quot;);					tf_3.setText(&quot;&quot;);					tf_4.setText(&quot;&quot;);						&#125;				&#125;catch(NumberFormatException ee)				&#123;					JOptionPane.showMessageDialog(null, &quot;不能构成三角形!!!&quot;);					tf_1.setText(&quot;&quot;);					tf_2.setText(&quot;&quot;);					tf_3.setText(&quot;&quot;);					tf_4.setText(&quot;&quot;);				&#125;					&#125;		&#125;;		bt.addActionListener(a);	&#125;&#125;

