&gt; it=set.iterator();  //遍历 类student，储存为类it			while (it.hasNext()) 			&#123;				Student stu2=it.next(); //创一个名为stu2的类				//将stu2的信息存储inf				inf=&quot;学号:&quot;+stu2.getId()+&quot;  &quot;+&quot;姓名:&quot;+stu2.getName()+&quot;\n&quot;				   +&quot;性别:&quot;+stu2.getSex()+&quot;  &quot;+&quot;年龄:&quot;+stu2.getAge()+&quot;\n&quot;				   +&quot;专业:&quot;+stu2.getMajor()+&quot;  &quot;+&quot;成绩:&quot;+stu2.getScore()+&quot;\n&quot;;				bt=inf.getBytes(); //把inf转换为2进制存储bt集合				bout.write(bt);								//分割线				bt=&quot;………………………………………………………………………………\n&quot;.getBytes();				bout.write(bt);				//清空缓存输入 				bout.flush();			&#125;			bout.close(); //关闭bout						//关闭fout			if(fout!=null) 			&#123;				try				&#123;					fout.close();				&#125; catch (IOException e2)				&#123;									&#125;			&#125;		&#125; catch (IOException e)		&#123;						e.printStackTrace();		&#125;		&#125;		&#125;

